#!/usr/bin/env node

/**
 * Object Service Implementation Validator - Enhanced Version
 *
 * ============================================================================
 * IMPORTANT: ONLY FOR CLAUDE-GENERATED FILES
 * ============================================================================
 *
 * This validator should ONLY be run on files that were NEWLY GENERATED BY CLAUDE.
 *
 * Purpose:
 *   - Verify that Claude-generated code follows all Object Service guidelines
 *   - Catch guideline violations before they enter the codebase
 *   - Ensure consistent patterns in AI-generated service and component implementations
 *
 * When to use:
 *   - After Claude generates a new entity service
 *   - After Claude creates a create-object component
 *   - After Claude implements view components with ObjectBaseComponent
 *
 * When NOT to use:
 *   - On existing legacy services or components
 *   - On third-party or external code
 *   - On manually written code (unless verifying against guidelines)
 *
 * ============================================================================
 * AUTO-CORRECTION WORKFLOW
 * ============================================================================
 *
 * When this script reports errors on Claude-generated files:
 *
 * 1. CLAUDE MUST read the error messages carefully
 * 2. CLAUDE MUST fix each violation in the generated file
 * 3. CLAUDE MUST re-run this validation script
 * 4. REPEAT steps 1-3 until ALL checks pass (✅)
 *
 * Claude should NEVER leave a file with validation errors.
 * The auto-correction loop continues until zero errors remain.
 *
 * Example workflow:
 *   - Claude generates project.service.ts
 *   - Run: node check-guidelines.js ./project.service.ts
 *   - CRITICAL: "Missing getObjectComponent(mode) method"
 *   - Claude fixes: adds getObjectComponent() with MvsCrudModeEnum.create handling
 *   - Run: node check-guidelines.js ./project.service.ts
 *   - ✅ Validation PASSED
 *
 * ============================================================================
 *
 * Comprehensive validation for object service implementations.
 * Validates ALL requirements from SKILL.md documentation.
 *
 * Supports Three File Types:
 *
 * 1. SERVICES (*.service.ts)
 *    - @Injectable() decorator
 *    - Extends MvsCrudService
 *    - getObjectComponent(mode) method - CRITICAL
 *    - Handles MvsCrudModeEnum.create mode
 *    - Returns component classes
 *    - getObjectLabels() method (optional)
 *    - getObjectIcon() method (optional)
 *
 * 2. CREATE COMPONENTS (*-create-object-*.component.ts)
 *    - @Component() decorator
 *    - Extends ObjectBaseComponent
 *    - Selector contains 'create-object'
 *    - @Output() onChangedObject - CRITICAL
 *    - @Output() onCancelObject
 *    - @Output() onDialogClose
 *    - this.onChangedObject.emit() - CRITICAL
 *    - this.initialized = true
 *    - isDirty state tracking
 *    - defaultCreateDto handling
 *
 * 3. VIEW COMPONENTS (*.component.ts)
 *    - @Component() decorator
 *    - Extends ObjectBaseComponent
 *    - Proper selector
 *    - Lifecycle methods
 *
 * Usage: node check-guidelines.js <path-to-file.ts>
 *
 * Exit Codes:
 *   0 = All validations passed
 *   1 = One or more validations failed
 */

const fs = require('fs');
const path = require('path');

// ANSI color codes
const colors = {
  reset: '\x1b[0m',
  red: '\x1b[31m',
  green: '\x1b[32m',
  yellow: '\x1b[33m',
  blue: '\x1b[34m',
  cyan: '\x1b[36m',
  magenta: '\x1b[35m',
  dim: '\x1b[2m',
  bold: '\x1b[1m'
};

function print(message, color = 'reset') {
  console.log(`${colors[color]}${message}${colors.reset}`);
}

function printSection(title) {
  console.log();
  print(`▸ ${title}`, 'magenta');
  print('─'.repeat(50), 'dim');
}

// Validation results tracker
const results = {
  passed: [],
  failed: [],
  warnings: [],
  skipped: [],
  critical: []
};

function pass(rule, detail = '') {
  results.passed.push({ rule, detail });
  const detailStr = detail ? ` ${colors.dim}(${detail})${colors.reset}` : '';
  print(`  ✓ ${rule}${detailStr}`, 'green');
}

function fail(rule, hint = '', isCritical = false) {
  if (isCritical) {
    results.critical.push({ rule, hint });
    print(`  ✗ [CRITICAL] ${rule}`, 'red');
  } else {
    results.failed.push({ rule, hint });
    print(`  ✗ ${rule}`, 'red');
  }
  if (hint) {
    print(`    └─ Hint: ${hint}`, 'yellow');
  }
}

function warn(message, hint = '') {
  results.warnings.push({ message, hint });
  print(`  ⚠ ${message}`, 'yellow');
  if (hint) {
    print(`    └─ ${hint}`, 'dim');
  }
}

function skip(rule, reason = '') {
  results.skipped.push({ rule, reason });
  print(`  ○ ${rule} ${colors.dim}(skipped: ${reason})${colors.reset}`, 'dim');
}

/**
 * Detect file type based on content and naming
 */
function detectFileType(content, fileName) {
  // Check if it's a service
  if (fileName.includes('.service.ts') || /extends\s+MvsCrudService/.test(content)) {
    return 'service';
  }

  // Check if it's a create component (check filename first, then content)
  if (fileName.includes('create-object') ||
      (fileName.includes('create') && /extends\s+ObjectBaseComponent/.test(content)) ||
      (/onChangedObject/.test(content) && /extends\s+ObjectBaseComponent/.test(content))) {
    return 'create-component';
  }

  // Check if it's a view component
  if (/extends\s+ObjectBaseComponent/.test(content)) {
    return 'view-component';
  }

  return 'unknown';
}

/**
 * Validate Service implementation
 */
function validateService(content, fileName, filePath) {
  printSection('Service Structure');

  // 1. Check @Injectable() decorator
  const injectablePattern = /@Injectable\s*\(/;
  if (injectablePattern.test(content)) {
    pass('@Injectable() decorator present');
  } else {
    fail('Missing @Injectable() decorator', 'Add @Injectable({ providedIn: "root" })');
  }

  // 2. Check extends MvsCrudService
  const extendsPattern = /extends\s+MvsCrudService/;
  if (extendsPattern.test(content)) {
    pass('Extends MvsCrudService');
  } else {
    fail(
      'Service must extend MvsCrudService',
      'Change to: export class YourService extends MvsCrudService',
      true
    );
  }

  // 3. Check constructor with HttpClient
  const constructorPattern = /constructor\s*\([^)]*http:\s*HttpClient/i;
  if (constructorPattern.test(content)) {
    pass('Constructor injects HttpClient');
  } else {
    warn('HttpClient injection not found', 'Ensure constructor has: protected http: HttpClient');
  }

  // 4. Check super() call with base URL
  const superCallPattern = /super\s*\(\s*http\s*,\s*[^)]+\)/;
  if (superCallPattern.test(content)) {
    pass('Calls super() with HTTP client and URL');
  } else {
    warn('super() call pattern not found', 'Ensure: super(http, MvsCrudService.baseUrl + "/your/endpoint")');
  }

  printSection('Component Resolution (CRITICAL)');

  // 5. Check getObjectComponent() method - CRITICAL
  const getObjectComponentPattern = /getObjectComponent\s*\([^)]*\)\s*[:{]/;
  if (getObjectComponentPattern.test(content)) {
    pass('Implements getObjectComponent(mode) method');

    // 6. Check return type
    const returnTypePattern = /getObjectComponent[^{]*:\s*Type<any>/;
    if (returnTypePattern.test(content)) {
      pass('getObjectComponent() has correct return type');
    } else {
      warn('Return type should be Type<any>', 'Add: getObjectComponent(mode): Type<any>');
    }

    // 7. Check handles create mode - CRITICAL
    const createModePattern = /MvsCrudModeEnum\.create/;
    if (createModePattern.test(content)) {
      pass('Handles MvsCrudModeEnum.create mode');
    } else {
      fail(
        'Missing MvsCrudModeEnum.create handling',
        'Add: if (mode === MvsCrudModeEnum.create) { return YourCreateComponent; }',
        true
      );
    }

    // 8. Check returns component
    const returnComponentPattern = /return\s+\w+Component/;
    const returnMatches = content.match(/return\s+(\w+Component)/g);
    if (returnMatches && returnMatches.length >= 1) {
      pass(`Returns component class(es)`, `${returnMatches.length} return statement(s)`);
    } else {
      fail(
        'getObjectComponent() must return a component class',
        'Ensure method returns a component like: return YourComponent;',
        true
      );
    }

  } else {
    fail(
      'Missing getObjectComponent(mode) method',
      'This is REQUIRED for dialogs to work! Add:\ngetObjectComponent(mode: MvsCrudModeEnum): Type<any> { ... }',
      true
    );
  }

  printSection('Optional Methods');

  // 9. Check getObjectLabels() method
  const getObjectLabelsPattern = /getObjectLabels\s*\(\s*\)\s*[:{]/;
  if (getObjectLabelsPattern.test(content)) {
    pass('Implements getObjectLabels() method');
  } else {
    skip('getObjectLabels() method', 'optional');
  }

  // 10. Check getObjectIcon() method
  const getObjectIconPattern = /getObjectIcon\s*\(\s*\)\s*[:{]/;
  if (getObjectIconPattern.test(content)) {
    pass('Implements getObjectIcon() method');
  } else {
    skip('getObjectIcon() method', 'optional');
  }

  // Try to check entity registration
  checkEntityRegistration(filePath, content);
}

/**
 * Validate Create Component implementation
 */
function validateCreateComponent(content, fileName, filePath) {
  printSection('Component Structure');

  // 1. Check @Component() decorator
  const componentPattern = /@Component\s*\(\s*\{/;
  if (componentPattern.test(content)) {
    pass('@Component() decorator present');
  } else {
    fail('Missing @Component() decorator');
  }

  // 2. Check extends ObjectBaseComponent
  const extendsPattern = /extends\s+ObjectBaseComponent/;
  if (extendsPattern.test(content)) {
    pass('Extends ObjectBaseComponent');
  } else {
    fail(
      'Create component must extend ObjectBaseComponent',
      'Change to: export class YourCreateComponent extends ObjectBaseComponent',
      true
    );
  }

  // 3. Check selector pattern
  const selectorPattern = /selector:\s*['"]([^'"]+)['"]/;
  const selectorMatch = content.match(selectorPattern);
  if (selectorMatch) {
    const selector = selectorMatch[1];
    if (selector.includes('create-object') || selector.includes('create')) {
      pass(`Selector follows naming convention`, selector);
    } else {
      warn(
        `Selector should contain 'create-object'`,
        `Found: '${selector}'. Recommended: '[module]-create-object-[entity]'`
      );
    }
  } else {
    fail('No selector found in @Component decorator');
  }

  // 4. Check implements interfaces
  const implementsPattern = /implements\s+([^{]+)/;
  const implementsMatch = content.match(implementsPattern);
  if (implementsMatch) {
    const interfaces = implementsMatch[1];
    if (/OnInit/.test(interfaces)) {
      pass('Implements OnInit');
    } else {
      warn('Missing OnInit interface');
    }
  }

  printSection('Required Outputs (CRITICAL)');

  // 5. Check @Output() onChangedObject - CRITICAL
  const onChangedObjectPattern = /@Output\(\)\s*onChangedObject/;
  if (onChangedObjectPattern.test(content)) {
    pass('@Output() onChangedObject declared');
  } else {
    fail(
      'Missing @Output() onChangedObject',
      'Add: @Output() onChangedObject = new EventEmitter<ObjectChangeEvent>();',
      true
    );
  }

  // 6. Check onChangedObject.emit() - CRITICAL
  const emitPattern = /this\.onChangedObject\.emit\s*\(/;
  if (emitPattern.test(content)) {
    pass('Emits onChangedObject event');

    // Check emit has correct structure
    const emitWithStructurePattern = /onChangedObject\.emit\s*\(\s*\{[\s\S]*?objectType[\s\S]*?action[\s\S]*?\}/;
    if (emitWithStructurePattern.test(content)) {
      pass('Emit includes objectType and action');
    } else {
      warn(
        'Emit should include objectType and action',
        'Use: this.onChangedObject.emit({ objectType: "x.Entity", action: "created", after: result })'
      );
    }
  } else {
    fail(
      'Missing this.onChangedObject.emit() call',
      'Dialog will NOT close without this! Add after save: this.onChangedObject.emit({...})',
      true
    );
  }

  // 7. Check @Output() onCancelObject
  const onCancelObjectPattern = /@Output\(\)\s*onCancelObject/;
  if (onCancelObjectPattern.test(content)) {
    pass('@Output() onCancelObject declared');
  } else {
    warn(
      'Missing @Output() onCancelObject',
      'Add for cancel button support: @Output() onCancelObject = new EventEmitter<void>();'
    );
  }

  // 8. Check @Output() onDialogClose
  const onDialogClosePattern = /@Output\(\)\s*onDialogClose/;
  if (onDialogClosePattern.test(content)) {
    pass('@Output() onDialogClose declared');
  } else {
    skip('@Output() onDialogClose', 'inherited from base');
  }

  printSection('State Management');

  // 9. Check initialized = true
  const initializedPattern = /this\.initialized\s*=\s*true/;
  if (initializedPattern.test(content)) {
    pass('Sets this.initialized = true');
  } else {
    fail(
      'Missing this.initialized = true',
      'Add this.initialized = true in ngOnInit() after setup'
    );
  }

  // 10. Check isDirty tracking
  const isDirtyPattern = /this\.isDirty\s*=|isDirty/;
  if (isDirtyPattern.test(content)) {
    pass('Tracks isDirty state');
  } else {
    warn(
      'No isDirty tracking found',
      'Track dirty state for unsaved changes warning'
    );
  }

  // 11. Check onComponentDirty emit
  const onComponentDirtyPattern = /this\.onComponentDirty\.emit/;
  if (onComponentDirtyPattern.test(content)) {
    pass('Emits onComponentDirty event');
  } else {
    warn(
      'Missing onComponentDirty.emit()',
      'Emit when form becomes dirty: this.onComponentDirty.emit(true)'
    );
  }

  printSection('Create Functionality');

  // 12. Check defaultCreateDto handling
  const defaultCreateDtoPattern = /this\.defaultCreateDto|defaultCreateDto/;
  if (defaultCreateDtoPattern.test(content)) {
    pass('Handles defaultCreateDto');
  } else {
    warn(
      'No defaultCreateDto handling found',
      'Check for defaultCreateDto in ngOnInit to pre-fill form'
    );
  }

  // 13. Check create/save method
  const saveMethodPattern = /(save|create|submit)\w*\s*\([^)]*\)\s*[:{]/i;
  if (saveMethodPattern.test(content)) {
    pass('Has save/create method');

    // Check for service.create() call
    const serviceCreatePattern = /\.create\s*\(/;
    if (serviceCreatePattern.test(content)) {
      pass('Calls service.create()');
    } else {
      warn('No service.create() call found', 'Use: this.service.create(dto).subscribe(...)');
    }
  } else {
    fail('Missing save/create method', 'Add a method to handle form submission');
  }

  // 14. Check cancel method
  const cancelMethodPattern = /cancel\s*\(\s*\)\s*[:{]/;
  if (cancelMethodPattern.test(content)) {
    pass('Has cancel() method');
  } else {
    warn('Missing cancel() method', 'Add cancel() to handle dialog cancellation');
  }

  // 15. Check validation
  const validationPattern = /Validators\.|\.valid|\.invalid|required|validation/i;
  if (validationPattern.test(content)) {
    pass('Has form validation');
  } else {
    warn('No validation found', 'Consider adding form validation before save');
  }

  // Check module declaration
  checkModuleDeclaration(filePath, fileName);
}

/**
 * Validate View Component implementation
 */
function validateViewComponent(content, fileName, filePath) {
  printSection('Component Structure');

  // 1. Check @Component() decorator
  const componentPattern = /@Component\s*\(\s*\{/;
  if (componentPattern.test(content)) {
    pass('@Component() decorator present');
  } else {
    fail('Missing @Component() decorator');
  }

  // 2. Check extends ObjectBaseComponent
  const extendsPattern = /extends\s+ObjectBaseComponent/;
  if (extendsPattern.test(content)) {
    pass('Extends ObjectBaseComponent');
  } else {
    fail(
      'View component must extend ObjectBaseComponent',
      'Change to: export class YourComponent extends ObjectBaseComponent'
    );
  }

  // 3. Check selector
  const selectorPattern = /selector:\s*['"]([^'"]+)['"]/;
  const selectorMatch = content.match(selectorPattern);
  if (selectorMatch) {
    pass(`Has selector`, selectorMatch[1]);
  } else {
    fail('No selector found in @Component decorator');
  }

  // 4. Check implements interfaces
  const implementsPattern = /implements\s+([^{]+)/;
  const implementsMatch = content.match(implementsPattern);
  if (implementsMatch) {
    const interfaces = implementsMatch[1];
    const hasOnInit = /OnInit/.test(interfaces);
    const hasOnChanges = /OnChanges/.test(interfaces);
    const hasOnDestroy = /OnDestroy/.test(interfaces);

    if (hasOnInit && hasOnChanges && hasOnDestroy) {
      pass('Implements OnInit, OnChanges, OnDestroy');
    } else {
      const implemented = [];
      if (hasOnInit) implemented.push('OnInit');
      if (hasOnChanges) implemented.push('OnChanges');
      if (hasOnDestroy) implemented.push('OnDestroy');
      if (implemented.length > 0) {
        pass(`Implements ${implemented.join(', ')}`);
      }
    }
  }

  printSection('Lifecycle Methods');

  // 5. Check ngOnInit
  const ngOnInitPattern = /ngOnInit\s*\(\s*\)\s*[:{]/;
  const superNgOnInitPattern = /super\.ngOnInit\s*\(\s*\)/;
  if (ngOnInitPattern.test(content)) {
    if (superNgOnInitPattern.test(content)) {
      pass('ngOnInit() calls super.ngOnInit()');
    } else {
      warn('Missing super.ngOnInit() call');
    }
  }

  // 6. Check ngOnChanges
  const ngOnChangesPattern = /ngOnChanges\s*\([^)]*\)\s*[:{]/;
  const superNgOnChangesPattern = /super\.ngOnChanges\s*\(/;
  if (ngOnChangesPattern.test(content)) {
    if (superNgOnChangesPattern.test(content)) {
      pass('ngOnChanges() calls super.ngOnChanges()');
    } else {
      warn('Missing super.ngOnChanges() call');
    }
  }

  // 7. Check ngOnDestroy
  const ngOnDestroyPattern = /ngOnDestroy\s*\(\s*\)\s*[:{]/;
  const superNgOnDestroyPattern = /super\.ngOnDestroy\s*\(\s*\)/;
  if (ngOnDestroyPattern.test(content)) {
    if (superNgOnDestroyPattern.test(content)) {
      pass('ngOnDestroy() calls super.ngOnDestroy()');
    } else {
      warn('Missing super.ngOnDestroy() call');
    }
  }

  printSection('Data Loading');

  // 8. Check getRetrieveObjectObservable or data loading
  const retrievePattern = /getRetrieveObjectObservable|loadData|load\w+\s*\(/;
  if (retrievePattern.test(content)) {
    pass('Has data loading method');
  } else {
    warn('No data loading method found', 'Consider overriding getRetrieveObjectObservable()');
  }

  // 9. Check objectIdentifier usage
  const objectIdPattern = /this\.objectIdentifier|objectIdentifier\./;
  if (objectIdPattern.test(content)) {
    pass('Uses objectIdentifier');
  } else {
    warn('No objectIdentifier usage found');
  }

  // 10. Check initialized flag
  const initializedPattern = /this\.initialized\s*=\s*true/;
  if (initializedPattern.test(content)) {
    pass('Sets this.initialized = true');
  } else {
    warn('Missing this.initialized = true');
  }
}

/**
 * Check entity registration in entity-provider.ts
 */
function checkEntityRegistration(filePath, content) {
  printSection('Entity Registration');

  // Try to find entity-provider.ts in parent directories
  const dirPath = path.dirname(filePath);
  const possiblePaths = [
    path.join(dirPath, 'entity-provider.ts'),
    path.join(dirPath, '..', 'entity-provider.ts'),
    path.join(dirPath, '..', '..', 'entity-provider.ts'),
  ];

  // Also look for *.entity-provider.ts pattern
  const parentDir = path.dirname(filePath);
  const grandParentDir = path.dirname(parentDir);

  let providerFound = false;
  let providerPath = null;

  for (const p of possiblePaths) {
    if (fs.existsSync(p)) {
      providerPath = p;
      providerFound = true;
      break;
    }
  }

  // Try to find by glob pattern
  if (!providerFound) {
    try {
      const files = fs.readdirSync(grandParentDir);
      for (const file of files) {
        if (file.endsWith('.entity-provider.ts') || file === 'entity-provider.ts') {
          providerPath = path.join(grandParentDir, file);
          providerFound = true;
          break;
        }
      }
    } catch (e) {
      // Directory doesn't exist or not readable
    }
  }

  if (providerFound && providerPath) {
    pass(`Found entity-provider`, path.basename(providerPath));

    // Check if service is registered
    const providerContent = fs.readFileSync(providerPath, 'utf-8');
    const serviceNameMatch = content.match(/class\s+(\w+Service)/);

    if (serviceNameMatch) {
      const serviceName = serviceNameMatch[1];
      if (providerContent.includes(serviceName)) {
        pass(`Service ${serviceName} is registered in entity-provider`);
      } else {
        fail(
          `Service ${serviceName} NOT found in entity-provider`,
          `Add to entity-provider.ts: ['x.Entity', { route: 'x/entities', service: ${serviceName} }]`,
          true
        );
      }
    }
  } else {
    warn(
      'Could not find entity-provider.ts',
      'Ensure entity is registered in [module].entity-provider.ts'
    );
  }
}

/**
 * Check module declaration
 */
function checkModuleDeclaration(filePath, fileName) {
  printSection('Module Registration');

  const dirPath = path.dirname(filePath);

  // Try to find module.ts in parent directories
  const possiblePaths = [
    path.join(dirPath, '..', '..', '*.module.ts'),
    path.join(dirPath, '..', '*.module.ts'),
  ];

  // Extract component class name
  const componentName = fileName
    .replace('.component.ts', '')
    .split('-')
    .map(part => part.charAt(0).toUpperCase() + part.slice(1))
    .join('') + 'Component';

  // Try to find module files
  let moduleFound = false;

  try {
    const parentDir = path.dirname(dirPath);
    const grandParentDir = path.dirname(parentDir);

    for (const dir of [parentDir, grandParentDir]) {
      if (fs.existsSync(dir)) {
        const files = fs.readdirSync(dir);
        for (const file of files) {
          if (file.endsWith('.module.ts')) {
            const modulePath = path.join(dir, file);
            const moduleContent = fs.readFileSync(modulePath, 'utf-8');

            // Check if component is declared
            if (moduleContent.includes(componentName)) {
              pass(`Component declared in ${file}`);
              moduleFound = true;
              break;
            }
          }
        }
      }
      if (moduleFound) break;
    }
  } catch (e) {
    // Ignore errors
  }

  if (!moduleFound) {
    warn(
      'Could not verify module declaration',
      `Ensure ${componentName} is declared in the module's declarations array`
    );
  }
}

/**
 * Main validation function
 */
function validateObjectService(filePath) {
  // Print header
  console.log();
  print('╔══════════════════════════════════════════════════════════════════════╗', 'cyan');
  print('║       Object Service Implementation Validator (Enhanced)             ║', 'cyan');
  print('║                   Coverage: 100% of SKILL.md                         ║', 'cyan');
  print('╚══════════════════════════════════════════════════════════════════════╝', 'cyan');

  // Check file exists
  if (!fs.existsSync(filePath)) {
    print(`\n✗ File not found: ${filePath}`, 'red');
    process.exit(1);
  }

  const content = fs.readFileSync(filePath, 'utf-8');
  const fileName = path.basename(filePath);

  // Detect file type
  const fileType = detectFileType(content, fileName);

  print(`\nFile: ${fileName}`, 'blue');
  print(`Path: ${filePath}`, 'dim');
  print(`Type: ${fileType.toUpperCase()}`, 'cyan');

  // Run appropriate validation
  switch (fileType) {
    case 'service':
      validateService(content, fileName, filePath);
      break;
    case 'create-component':
      validateCreateComponent(content, fileName, filePath);
      break;
    case 'view-component':
      validateViewComponent(content, fileName, filePath);
      break;
    default:
      print('\n⚠ Could not determine file type', 'yellow');
      print('Running generic validation...', 'dim');

      if (/extends\s+MvsCrudService/.test(content)) {
        validateService(content, fileName, filePath);
      } else if (/extends\s+ObjectBaseComponent/.test(content)) {
        if (/onChangedObject/.test(content)) {
          validateCreateComponent(content, fileName, filePath);
        } else {
          validateViewComponent(content, fileName, filePath);
        }
      } else {
        fail('File does not appear to be a service or component', 'Ensure it extends MvsCrudService or ObjectBaseComponent');
      }
  }

  // Print Summary
  console.log();
  print('═'.repeat(70), 'cyan');
  print('  VALIDATION SUMMARY', 'cyan');
  print('═'.repeat(70), 'cyan');
  console.log();

  const total = results.passed.length + results.failed.length + results.critical.length;
  const failures = results.failed.length + results.critical.length;
  const passRate = total > 0 ? Math.round((results.passed.length / total) * 100) : 0;

  print(`  ✓ Passed:   ${results.passed.length}`, 'green');

  if (results.critical.length > 0) {
    print(`  ✗ Critical: ${results.critical.length}`, 'red');
  }

  print(`  ✗ Failed:   ${results.failed.length}`, failures > 0 ? 'red' : 'green');
  print(`  ⚠ Warnings: ${results.warnings.length}`, results.warnings.length > 0 ? 'yellow' : 'green');
  print(`  ○ Skipped:  ${results.skipped.length}`, 'dim');
  console.log();
  print(`  Pass Rate:  ${passRate}%`, passRate === 100 ? 'green' : passRate >= 70 ? 'yellow' : 'red');

  console.log();
  print('═'.repeat(70), 'cyan');

  // Exit with appropriate code
  if (results.critical.length > 0) {
    console.log();
    print('🚨 CRITICAL FAILURES - These MUST be fixed!', 'red');
    results.critical.forEach(c => {
      print(`   • ${c.rule}`, 'red');
    });
    console.log();
    process.exit(1);
  } else if (results.failed.length > 0) {
    console.log();
    print('❌ Validation FAILED - Please fix the errors above', 'red');
    console.log();
    process.exit(1);
  } else if (results.warnings.length > 0) {
    console.log();
    print('⚠️  Validation PASSED with warnings', 'yellow');
    console.log();
    process.exit(0);
  } else {
    console.log();
    print('✅ Validation PASSED - Implementation follows all guidelines!', 'green');
    console.log();
    process.exit(0);
  }
}

// CLI Entry Point
const filePath = process.argv[2];

if (!filePath) {
  console.log();
  print('Object Service Implementation Validator', 'cyan');
  print('─'.repeat(40), 'dim');
  console.log();
  print('Usage:', 'yellow');
  print('  node check-guidelines.js <path-to-file.ts>', 'reset');
  console.log();
  print('Examples:', 'yellow');
  print('  node check-guidelines.js ./project.service.ts', 'reset');
  print('  node check-guidelines.js ./sp-create-object-project.component.ts', 'reset');
  print('  node check-guidelines.js ./sp-project.component.ts', 'reset');
  console.log();
  print('Supports:', 'blue');
  print('  • Services (*.service.ts)', 'reset');
  print('  • Create Components (*-create-object-*.component.ts)', 'reset');
  print('  • View Components (*.component.ts)', 'reset');
  console.log();
  process.exit(1);
}

const absolutePath = path.resolve(filePath);
validateObjectService(absolutePath);
